def tokens(name: str):
    return [t for t in name.replace(',', ' ').split() if t]

print(tokens('Quispe, Ana María'))

def jaccard(a: str, b: str) -> float:
    sa, sb = set(a.casefold()), set(b.casefold())
    if not sa and not sb:
        return 1.0
    return len(sa & sb) / len(sa | sb)

print(round(jaccard('Ana', 'Ana'), 2))
print(round(jaccard('Ana', 'Anb'), 2))

def token_jaccard(a, b):
    sa, sb = set(a.casefold().split()), set(b.casefold().split())
    if not sa and not sb:
        return 1.0
    return len(sa & sb) / len(sa | sb)

print(round(token_jaccard('Ana Quispe', 'Ana Rojas'), 2))

