def same_doc(a, b):
    def norm(x):
        return ''.join(ch for ch in x.casefold() if ch.isalnum())
    return norm(a) == norm(b)

print(same_doc('DNI-123', 'dni123'))
print(same_doc('DNI-123', 'DNI-999'))

