# NFC antes de comparar / hashear nombres
import unicodedata, hashlib
def nfc(s):
    return unicodedata.normalize('NFC', s)
a, b = 'José', 'Jose\u0301'
print(hashlib.sha256(nfc(a).encode()).hexdigest() == hashlib.sha256(nfc(b).encode()).hexdigest())

def safe_preview(s, n=20):
    return (s[:n] + '…') if len(s) > n else s

print(safe_preview('abcdefghijklmnopqrstuvwxyz'))
